    60  RendererSandboxedProcessLauncherDelegateWin::
    61      RendererSandboxedProcessLauncherDelegateWin(
    62          const base::CommandLine& cmd_line,
    63          bool is_pdf_renderer,
    64          bool is_jit_disabled)
    65      : renderer_code_integrity_enabled_(
    66            GetContentClient()->browser()->IsRendererCodeIntegrityEnabled()),
    67        renderer_app_container_disabled_(
    68            GetContentClient()->browser()->IsAppContainerDisabled(
    69                sandbox::mojom::Sandbox::kRenderer)),
    70        is_pdf_renderer_(is_pdf_renderer) {
    71    // PDF renderers must be jitless.
    72    CHECK(!is_pdf_renderer || is_jit_disabled);
    73    if (is_jit_disabled) {
    74      dynamic_code_can_be_disabled_ = true;
    75      return;
    76    }
    77    if (cmd_line.HasSwitch(blink::switches::kJavaScriptFlags)) {
    78      std::string js_flags =
    79          cmd_line.GetSwitchValueASCII(blink::switches::kJavaScriptFlags);
    80      std::vector<std::string_view> js_flag_list = base::SplitStringPiece(
    81          js_flags, ",", base::TRIM_WHITESPACE, base::SPLIT_WANT_NONEMPTY);
    82      for (const auto& js_flag : js_flag_list) {
    83        if (js_flag == "--jitless") {
    84          // If v8 is running jitless then there is no need for the ability to
    85          // mark writable pages as executable to be available to the process.
    86          dynamic_code_can_be_disabled_ = true;
    87          break;
    88        }
    89      }
    90    }
    91  }
