   149  void RendererSandboxedProcessLauncherDelegateWin::PostSpawnTarget(
   150      base::ProcessHandle process) {
   151    FILETIME creation_time, exit_time, kernel_time, user_time;
   152    // Should never fail. If it does, then something really bad has happened, such
   153    // as something external unsuspending the renderer process.
   154    if (!::GetProcessTimes(process, &creation_time, &exit_time, &kernel_time,
   155                           &user_time)) {
   156      return;
   157    }
   158
   159    // These should always be zero but if they are not, then something on the
   160    // client has triggered execution in the child process putting it into a
   161    // undefined state. Try and detect this here to diagnose this happening in the
   162    // wild.
   163    base::UmaHistogramBoolean(
   164        "BrowserRenderProcessHost.SuspendedChild.UserExecutionRecorded",
   165        base::TimeDelta::FromFileTime(user_time).InMicroseconds() > 0);
   166    base::UmaHistogramBoolean(
   167        "BrowserRenderProcessHost.SuspendedChild.KernelExecutionRecorded",
   168        base::TimeDelta::FromFileTime(kernel_time).InMicroseconds() > 0);
   169  }
