   191  sandbox::mojom::Sandbox SandboxTypeFromCommandLine(
   192      const base::CommandLine& command_line) {
   193    if (command_line.HasSwitch(switches::kNoSandbox))
   194      return Sandbox::kNoSandbox;
   195
   196    std::string process_type =
   197        command_line.GetSwitchValueASCII(switches::kProcessType);
   198    if (process_type.empty())
   199      return Sandbox::kNoSandbox;
   200
   201    if (process_type == switches::kRendererProcess)
   202      return Sandbox::kRenderer;
   203
   204    if (process_type == switches::kUtilityProcess) {
   205      return UtilitySandboxTypeFromString(
   206          command_line.GetSwitchValueASCII(switches::kServiceSandboxType));
   207    }
   208    if (process_type == switches::kGpuProcess) {
   209      if (command_line.HasSwitch(switches::kDisableGpuSandbox))
   210        return Sandbox::kNoSandbox;
   211      return Sandbox::kGpu;
   212    }
   213
   214  #if BUILDFLAG(ENABLE_PPAPI) && !BUILDFLAG(IS_WIN)
   215    if (process_type == switches::kPpapiPluginProcess)
   216      return Sandbox::kPpapi;
   217  #endif
   218
   219    // NaCl tests on all platforms use the loader process.
   220    if (process_type == switches::kNaClLoaderProcess) {
   221      return Sandbox::kUtility;
   222    }
   223
   224  #if BUILDFLAG(IS_LINUX) || BUILDFLAG(IS_CHROMEOS)
   225    // Intermediate process gains a sandbox later.
   226    if (process_type == switches::kZygoteProcessType)
   227      return Sandbox::kZygoteIntermediateSandbox;
   228  #endif
   229
   230  #if BUILDFLAG(IS_MAC)
   231    if (process_type == switches::kRelauncherProcessType ||
   232        process_type == switches::kCodeSignCloneCleanupProcessType) {
   233      return Sandbox::kNoSandbox;
   234    }
   235  #endif
   236
   237    NOTREACHED()
   238        << "Command line does not provide a valid sandbox configuration: "
   239        << command_line.GetCommandLineString();
   240  }
